def minPath(grid, k):
    n = len(grid)

    # Find the position of each value in the grid
    pos = {}
    for i in range(n):
        for j in range(n):
            pos[grid[i][j]] = (i, j)

    # Start from the cell with value 1
    start_i, start_j = pos[1]

    # DFS with memoization to find the minimum path
    memo = {}

    def dfs(i, j, remaining):
        # remaining is the number of cells we still need to visit
        if remaining == 0:
            return []

        if (i, j, remaining) in memo:
            return memo[(i, j, remaining)]

        current_val = grid[i][j]

        # If this is the last cell we need to visit
        if remaining == 1:
            return [current_val]

        # Try all four directions
        best_path = None
        directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]

        for di, dj in directions:
            ni, nj = i + di, j + dj

            # Check bounds
            if 0 <= ni < n and 0 <= nj < n:
                next_path = dfs(ni, nj, remaining - 1)
                candidate = [current_val] + next_path

                # Update best_path if this is better lexicographically
                if best_path is None or candidate < best_path:
                    best_path = candidate

        memo[(i, j, remaining)] = best_path
        return best_path

    result = dfs(start_i, start_j, k)
    return result
